UPDATE users
SET nickname = #{nickname},
    email = #{email},
    phone = #{phone}
WHERE user_seq = #{userSeq}

UPDATE stores
SET biz_number = #{bizNumber},
    company_name = #{companyName},
    ceo_name = #{ceoName},    
    zonecode = #{zonecode},
    address1 = #{address1},
    address2 = #{address2}
WHERE user_seq = #{userSeq}


    AND store_seq = #{storeSeq}



    AND store_seq = (SELECT MAX(store_seq) FROM (SELECT store_seq FROM stores WHERE user_seq = #{userSeq}) AS tmp)

UPDATE users
SET alert_stock_yn = #{alertStockYn},
    alert_expiry_yn = #{alertExpiryYn},
    alert_order_yn = #{alertOrderYn}
WHERE user_seq = #{userSeq}
